import json, sys

schema = json.load(open('schema.json'))
manifest = json.load(open('manifest.json'))

import re

errors = []

# Check additionalProperties at root
allowed_root = set(schema['properties'].keys())
for key in manifest:
    if key not in allowed_root:
        errors.append(f'Unexpected root key: {key}')

# Check release
release = manifest.get('release', '')
if not re.match(r'^v[0-9]+\.[0-9]+\.[0-9]+$', release):
    errors.append(f'release does not match pattern: {release}')
else:
    print(f'release: {release} OK')

# Check components
components = manifest.get('components', None)
if not isinstance(components, list):
    errors.append('components must be an array')
elif len(components) != 3:
    errors.append(f'components must have exactly 3 items, got {len(components)}')
else:
    for i, c in enumerate(components):
        extra = set(c.keys()) - {'name', 'version'}
        if extra:
            errors.append(f'component[{i}] has extra keys: {extra}')
        if not isinstance(c.get('name'), str) or len(c.get('name','')) == 0:
            errors.append(f'component[{i}] name invalid')
        if not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+$', c.get('version','')):
            errors.append(f'component[{i}] version invalid: {c.get(\"version\")}')
    # Check uniqueness
    seen = []
    for c in components:
        if c in seen:
            errors.append(f'duplicate component: {c}')
        seen.append(c)
    # Check order
    expected_names = ['catalog', 'fetcher', 'leaderboard']
    actual_names = [c['name'] for c in components]
    if actual_names != expected_names:
        errors.append(f'wrong order: {actual_names}')
    else:
        print(f'components order: {actual_names} OK')
    print('components:', json.dumps(components, indent=2))

if errors:
    print('ERRORS:', errors)
    sys.exit(1)
else:
    print('ALL CHECKS PASSED')
"

